import os
import shlex
import subprocess
import tempfile
from google.cloud import storage

storage_client = storage.Client()

def process_image(event, context):
    bucket_name = event["bucket"]
    source_name = event["name"]
    metadata = event.get("metadata") or {}

    filename = metadata.get("filename", source_name)
    options = metadata.get("options", "")

    bucket = storage_client.bucket(bucket_name)
    blob = bucket.blob(source_name)

    with tempfile.TemporaryDirectory() as tmpdir:
        input_path = os.path.join(tmpdir, os.path.basename(filename))
        output_path = os.path.join(tmpdir, "output_" + os.path.basename(filename))

        blob.download_to_filename(input_path)

        cmd = "convert " + input_path + " " + options + " " + output_path
        subprocess.call(cmd, shell=True)

        output_blob = bucket.blob("processed/" + os.path.basename(output_path))
        output_blob.upload_from_filename(output_path)